import os
import time
import hmac
import struct
import hashlib
import base64
import secrets
from functools import wraps
from flask import Flask, request, jsonify, session, redirect, url_for, render_template_string

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# In-memory user store (replace with database in production)
USERS = {
    "admin": {
        "password_hash": hashlib.sha256("admin123".encode()).hexdigest(),
        "mfa_secret": base64.b32encode(secrets.token_bytes(20)).decode('utf-8'),
        "mfa_enabled": True,
    },
    "user1": {
        "password_hash": hashlib.sha256("password1".encode()).hexdigest(),
        "mfa_secret": base64.b32encode(secrets.token_bytes(20)).decode('utf-8'),
        "mfa_enabled": True,
    },
    "user2": {
        "password_hash": hashlib.sha256("password2".encode()).hexdigest(),
        "mfa_secret": None,
        "mfa_enabled": False,
    },
}

# Track pending MFA sessions and background verification status
PENDING_MFA = {}


def generate_totp(secret, time_step=30, digits=6):
    """Generate a TOTP code from a base32-encoded secret."""
    key = base64.b32decode(secret, casefold=True)
    counter = int(time.time()) // time_step
    counter_bytes = struct.pack('>Q', counter)
    hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
    offset = hmac_hash[-1] & 0x0F
    truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
    code = truncated % (10 ** digits)
    return str(code).zfill(digits)


def verify_totp(secret, code, time_step=30, window=1):
    """Verify a TOTP code with a time window tolerance."""
    for i in range(-window, window + 1):
        key = base64.b32decode(secret, casefold=True)
        counter = (int(time.time()) // time_step) + i
        counter_bytes = struct.pack('>Q', counter)
        hmac_hash = hmac.new(key, counter_bytes, hashlib.sha1).digest()
        offset = hmac_hash[-1] & 0x0F
        truncated = struct.unpack('>I', hmac_hash[offset:offset + 4])[0] & 0x7FFFFFFF
        expected = str(truncated % (10 ** 6)).zfill(6)
        if hmac.compare_digest(expected, code):
            return True
    return False


def login_required(f):
    """Decorator: requires at least password authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login_page'))
        return f(*args, **kwargs)
    return decorated


def mfa_required(f):
    """Decorator: requires full MFA verification."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login_page'))
        username = session.get('username')
        user = USERS.get(username)
        if user and user.get('mfa_enabled') and not session.get('mfa_verified'):
            return redirect(url_for('verify_mfa_page'))
        return f(*args, **kwargs)
    return decorated


def partial_access_allowed(f):
    """Decorator: allows access after password auth, MFA can be pending."""
    @wraps(f)
    def decorated(*args, **kwargs):
        if not session.get('authenticated'):
            return redirect(url_for('login_page'))
        return f(*args, **kwargs)
    return decorated


